package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtTypeAccess;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;
import java.util.Optional;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java -jar transformation.jar <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create Spoon launcher
        Launcher launcher = new Launcher();
        launcher.getEnvironment().setComplianceLevel(8);
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "_fixed");

        // Process the code
        CtModel model = launcher.buildModel();

        // Fix 1: Remove imports of PublishMetadata class
        fixPublishMetadataImports(model);

        // Fix 2: Replace Publisher<PublishMetadata> with Publisher<Message>
        fixPublisherType(model);

        // Fix 3: Remove setContext calls 
        fixSetContextCalls(model);

        // Save the fixed code
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation completed successfully!");
    }

    private static void fixPublishMetadataImports(CtModel model) {
        // Remove imports of PublishMetadata
        model.getElements(new TypeFilter<CtImport>(CtImport.class) {
            @Override
            public boolean matches(CtImport element) {
                return element.getReference() != null && 
                       element.getReference().getSimpleName().equals("PublishMetadata");
            }
        }).forEach(importElement -> {
            importElement.delete();
        });
    }

    private static void fixPublisherType(CtModel model) {
        // Find all type references to Publisher<PublishMetadata>
        model.getElements(new TypeFilter<CtTypeReference<?>>(CtTypeReference.class) {
            @Override
            public boolean matches(CtTypeReference<?> element) {
                return element.getQualifiedName().equals("com.google.cloud.pubsublite.internal.Publisher") &&
                       element.getActualTypeArguments().size() == 1 &&
                       element.getActualTypeArguments().get(0).getQualifiedName().equals("com.google.cloud.pubsublite.PublishMetadata");
            }
        }).forEach(publisherTypeRef -> {
            // Replace with Publisher<Message>
            CtTypeReference<?> newTypeRef = publisherTypeRef.getFactory().createTypeReference("com.google.cloud.pubsublite.internal.Publisher");
            newTypeRef.addActualTypeArgument(publisherTypeRef.getFactory().createTypeReference("com.google.cloud.pubsublite.Message"));
            publisherTypeRef.replace(newTypeRef);
        });

        // Find all class declarations that have Publisher<PublishMetadata> in their type parameters
        model.getElements(new TypeFilter<CtClass<?>>(CtClass.class) {
            @Override
            public boolean matches(CtClass<?> element) {
                return element.getSuperclass() != null &&
                       element.getSuperclass().getQualifiedName().equals("com.google.cloud.pubsublite.internal.Publisher") &&
                       element.getSuperclass().getActualTypeArguments().size() == 1 &&
                       element.getSuperclass().getActualTypeArguments().get(0).getQualifiedName().equals("com.google.cloud.pubsublite.PublishMetadata");
            }
        }).forEach(clazz -> {
            // Replace with Publisher<Message>
            CtTypeReference<?> newSuperclass = clazz.getFactory().createTypeReference("com.google.cloud.pubsublite.internal.Publisher");
            newSuperclass.addActualTypeArgument(clazz.getFactory().createTypeReference("com.google.cloud.pubsublite.Message"));
            clazz.setSuperclass(newSuperclass);
        });
    }

    private static void fixSetContextCalls(CtModel model) {
        // Find all method calls to setContext
        model.getElements(new TypeFilter<CtInvocation<?>>(CtInvocation.class) {
            @Override
            public boolean matches(CtInvocation<?> element) {
                return element.getExecutable() != null && 
                       element.getExecutable().getSimpleName().equals("setContext");
            }
        }).forEach(invocation -> {
            // Find the parent expression that contains the call
            CtExpression<?> parent = invocation.getParent(CtExpression.class);
            if (parent != null) {
                // Remove the entire setContext call and associated builder chain
                parent.delete();
            }
        });
    }
}

