            .build();
    builder.setTopic(topic);
    builder.setPublisherFactory(
        partition ->
            SinglePartitionPublisherBuilder.newBuilder()
                .setTopic(topic)
                .setPartition(partition)
                .build());
    return builder.build();
  }
}

